package com.hospital.management.controller.admission;import com.hospital.management.model.Bed;import com.hospital.management.service.*;import com.hospital.management.service.impl.BedServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;import java.util.*;@WebServlet("/admissions/available-beds")public class AvailableBedsServlet extends HttpServlet{private final BedService service;public AvailableBedsServlet(){this(new BedServiceImpl());}public AvailableBedsServlet(BedService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{Long dep=AdmissionRequest.id(q.getParameter("departmentId"));List<Bed>x=service.getAvailableBeds(dep,q.getParameter("roomType"));r.setCharacterEncoding("UTF-8");r.setContentType("application/json");StringBuilder j=new StringBuilder("[");for(int i=0;i<x.size();i++){Bed b=x.get(i);if(i>0)j.append(',');j.append("{\"bedId\":").append(b.getBedId()).append(",\"bedNumber\":\"").append(esc(b.getBedNumber())).append("\",\"roomNumber\":\"").append(esc(b.getRoomNumber())).append("\",\"roomType\":\"").append(esc(b.getRoomType())).append("\",\"dailyRate\":\"").append(b.getDailyRate()).append("\"}");}r.getWriter().write(j.append(']').toString());}private String esc(String s){return s==null?"":s.replace("\\","\\\\").replace("\"","\\\"");}}
